  long_context_or_creative: 'large',
}

const TIER_TO_PROVIDER: Record<Tier, ProviderId> = {
  small: 'gemma-local',
  medium: 'gemma-local',
  large: 'cloud',
}

const bumpUp = (t: Tier): Tier => (t === 'small' ? 'medium' : 'large')

const fetchWithTimeout = (url: string, init: RequestInit, timeoutMs: number): Promise<Response> => {
  const controller = new AbortController()
  const timer = setTimeout(() => controller.abort(), timeoutMs)
  return fetch(url, { ...init, signal: controller.signal }).finally(() => clearTimeout(timer))
}

export const routerService = {
  manual(provider: ProviderId): RouteDecision {
    return {
      tier: provider === 'cloud' ? 'large' : 'medium',
      provider,
      label: 'manual',
      confidence: 1,
      latencyMs: 0,
      routed: false,
    }
  },

  async classify(message: string, history: string[], fallbackProvider: ProviderId): Promise<RouteDecision> {
    const start = performance.now()
    if (!FASTINO_API_KEY) {
      return fallback('missing-key', start, fallbackProvider)
    }

    try {
      const ctx = history.slice(-3).join('\n')
      const response = await fetchWithTimeout(FASTINO_ENDPOINT, {
        method: 'POST',
        headers: {
          'x-api-key': FASTINO_API_KEY,
          'content-type': 'application/json',
        },
        body: JSON.stringify({
          model_id: 'fastino-classification-en',
          input: [{
            text: `${ctx}\n\nuser: ${message}`,
            parameters: {
              classifications: [{ task: 'intent', labels: FASTINO_LABELS }],
            },
          }],
        }),
      }, FASTINO_TIMEOUT_MS)

      if (!response.ok) return fallback(`http-${response.status}`, start, fallbackProvider)
      const data = await response.json()
      const classification = data?.output?.[0]?.classifications?.[0]
      const label: string = classification?.label ?? 'reasoning_or_code'
      const confidence: number = classification?.confidence ?? 0
      let tier = LABEL_TO_TIER[label] ?? 'medium'
      if (confidence < 0.6) tier = bumpUp(tier)

      return {
        tier,
        provider: TIER_TO_PROVIDER[tier],
        label,
        confidence,
        latencyMs: performance.now() - start,
        routed: true,
      }
    } catch (e) {
      return fallback(`exception:${(e as Error).name}`, start, fallbackProvider)
    }
  },
}

const fallback = (reason: string, start: number, provider: ProviderId): RouteDecision => ({
  tier: provider === 'cloud' ? 'large' : 'medium',
  provider,
  label: `fallback:${reason}`,
  confidence: 0,
  latencyMs: performance.now() - start,
  routed: false,
})

