    21	// Decoding audio in fixed-size chunks because total frame count can't be
    22	// determined in advance. Note: ma_decoder_get_length_in_pcm_frames() always
    23	// returns 0 for Vorbis decoders.
    24	Result<std::vector<float>, std::string> AudioDecoder::readAllPcmFrames(
    25	    ma_decoder &decoder,
    26	    int outputChannels) {
    27	  std::vector<float> buffer;
    28	  std::vector<float> temp(CHUNK_SIZE * outputChannels);
    29	  ma_uint64 outFramesRead = 0;
    30	
    31	  while (true) {
    32	    ma_uint64 tempFramesDecoded = 0;
    33	    ma_decoder_read_pcm_frames(&decoder, temp.data(), CHUNK_SIZE, &tempFramesDecoded);
    34	    if (tempFramesDecoded == 0) {
    35	      break;
    36	    }
    37	
    38	    buffer.insert(buffer.end(), temp.data(), temp.data() + tempFramesDecoded * outputChannels);
    39	    outFramesRead += tempFramesDecoded;
    40	  }
    41	
    42	  if (outFramesRead == 0) {
    43	    return Err("Failed to decode any frames");
    44	  }
    45	
    46	  return Ok(std::move(buffer));
    47	}
