    49	AudioBufferResult AudioDecoder::makeAudioBufferFromFloatBuffer(
    50	    const std::vector<float> &buffer,
    51	    float outputSampleRate,
    52	    int outputChannels) {
    53	  if (buffer.empty()) {
    54	    return Err("Buffer is empty");
    55	  }
